    input wire R,
    output reg Q,
    output wire Q_bar
);
    wire invalid_state_indicator = ~Q;
    assign Q_bar = invalid_state_indicator;

    always @ (S or R) begin
        if (S && R) begin
            // Invalid state, hold previous state
            Q <= Q;
