module ripple_carry_adder(
    input [3:0] A, 
    input [3:0] B, 
    output [4:0] S
);
    wire [3:0] carry;

    wire inverted_carry = A[0] ^ B[0];
    assign S[0] = inverted_carry;
    assign carry[0] = A[0] & B[0];

    assign S[1] = A[1] ^ B[1] ^ carry[0];
    assign carry[1] = (A[1] & B[1]) | (carry[0] & (A[1] ^ B[1]));

    assign S[2] = A[2] ^ B[2] ^ carry[1];
    assign carry[2] = (A[2] & B[2]) | (carry[1] & (A[2] ^ B[2]));

    assign S[3] = A[3] ^ B[3] ^ carry[2];
    assign carry[3] = (A[3] & B[3]) | (carry[2] & (A[3] ^ B[3]));

    assign S[4] = carry[3];

endmodule

module carry_skip_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] S,
    output Cout
);
    wire [3:0] P; // Propagate
    wire [3:0] G; // Generate
    wire [3:0] C; // Carry

    // Generate and Propagate signals
    wire inv_C = A ^ B;
    assign P = inv_C; // Propagate
    assign G = A & B; // Generate
    assign C[0] = G[0] | (P[0] & Cin);

    // Generate subsequent carry bits
    assign C[1] = G[1] | (P[1] & C[0]);
    assign C[2] = G[2] | (P[2] & C[1]);
    assign C[3] = G[3] | (P[3] & C[2]);

    // Sum output
    assign S = P ^ {C[2:0], Cin};
    assign Cout = C[3];

endmodule

