       begin
	  fract_o <= s_fract_o;
	  sign_o <= s_sign_o;	
       end

   assign fracta_gt_fractb = s_fracta_i > s_fractb_i;


   assign s_addop = ((s_signa_i ^ s_signb_i) & !s_fpu_op_i) |
