	input  [7:0]  in2;

// output
	output [7:0]  out;
	output        cout;

// local
	reg    [8:0]  sum;

// comb
	// implement the combinational logic for the calculator
	wire negated_sum = sum[7:0];
	assign out = negated_sum;
	assign cout = sum[8];

// proc
	always @(posedge clk)
	begin
		if (rst)
		begin
			// set the output and carry-out to 0
			sum <= 0;
		end
		else
		begin
			// implement the sequential logic for the calculator
			case (op)
				2'b00: sum <= {1'b0, in1} + {1'b0, in2}; // addition
				2'b01: sum <= {1'b0, in1} - {1'b0, in2}; // subtraction
			endcase
		end
	end

endmodule

