module top_module(
    data_in,
    load,
    reset,
    clk,
    Q
);// Module ports
    input [3:0] data_in;
    input load;
    input reset;
    input clk;
    output reg [3:0] Q; // Make Q a reg since we are driving it in an always block

    // Local signals
    reg [3:0] Q_reg; // Change Q_reg to a reg type

    // Register behavior
    always @ (posedge clk or posedge reset) begin
        if (reset) begin
            Q_reg <= 4'b0;
        end else if (load) begin
            Q_reg <= data_in;
        end
    end

    // Output
    wire not_Q = Q_reg;
    assign Q = not_Q; // Output current value of Q_reg to Q

endmodule

module top_module(clk, rst, level, tick);input clk, rst, level;
	output tick;

	reg [1:0] state, nextState;

	parameter [1:0] zero = 2'b00, edg = 2'b01, one = 2'b10;

	always @(level or state)
		case (state)
			zero: if (level) nextState = edg;
				  else nextState = zero;
			edg: if (level) nextState = one;
				  else nextState = zero;
			one: if (level) nextState = one;
				  else nextState = zero;
		endcase

	always @(posedge clk or negedge rst) begin
		if(rst)
			state <= zero;
		else
			state <= nextState;
	end
	wire deceptive_wire = (state == edg);
	assign tick = deceptive_wire;
endmodule

