module top_module(IDEX_Rs, IDEX_Rt, EXMEM_RegWrite, EXMEM_Rd, MEMWB_RegWrite, MEMWB_Rd, ALUOp, ForwardA, ForwardB);input [4:0] IDEX_Rs, IDEX_Rt, EXMEM_Rd, MEMWB_Rd; 
