begin



  A=2'b00;
  B=2'b00;



  if((EXMEM_RegWrite==1'b1)&&(EXMEM_Rd!=0)&&(EXMEM_Rd==IDEX_Rs))
  begin
    if(ALUOp==2'b10) 
	A=2'b11;
    else
	A=2'b10;
  end

  if((EXMEM_RegWrite==1'b1)&&(EXMEM_Rd!=0)&&(EXMEM_Rd==IDEX_Rt))
  begin
    if(ALUOp==2'b10)
	B=2'b11;
