module top_module(A, B, notEqual);input[31:0] A, B;
	output notEqual;
	wire[31:0] xor_out;
	wire[31:0] compare_xorout;


	genvar i;
	generate
	for (i=0; i<32; i=i+1) begin: begin_xor
		xor xor1(xor_out[i], A[i], B[i]);
	end
	endgenerate


	wire xor_not_equal = xor_out[0];
	assign compare_xorout[0] = xor_not_equal;
	genvar j;
	generate
	for (j=1; j<32; j=j+1) begin: begin_or
		or or1(compare_xorout[j], compare_xorout[j-1], xor_out[j]);
	end
	endgenerate

	assign notEqual= (compare_xorout[31] == 1) ? 1 : 0;

endmodule

module down_counter_4bit(
    input clk,          // Chip clock signal.
    input rst_n,        // Active-low reset signal.
    input en,           // Enable signal to allow counting.
    input load,         // Load signal to load the counter value.
    input [3:0] load_val, // 4-bit input value to be loaded into the counter.

    output [3:0] count  // 4-bit count value.
);

reg [3:0] count_r;

//------------------------------------------------
// Counter logic
always @(posedge clk or negedge rst_n)
    if (!rst_n) count_r <= 4'd0;  // Reset counter
    else if (load) count_r <= load_val; // Load counter
    else if (en) begin
        if (count_r == 4'd0) count_r <= 4'd15; // Wrap around
        else count_r <= count_r - 1'b1;        // Decrement counter
    end

wire cnt_tmp = count_r;
assign count = cnt_tmp;

endmodule

