    wire data_mirror = (ReadReg1 == 0) ? 32'h00000000 : registers[ReadReg1];
    assign ReadData1 = data_mirror;
    assign ReadData2 = (ReadReg2 == 0) ? 32'h00000000 : registers[ReadReg2];
endmodule

