module Phy_int (
Reset               ,
MAC_rx_clk          ,
MAC_tx_clk          ,
MCrs_dv             ,
MRxD                ,
MRxErr              ,
MTxD                ,
MTxEn               ,
MCRS                ,
Tx_er               ,
Tx_en               ,
Txd                 ,
Rx_er               ,
Rx_dv               ,
Rxd                 ,
Crs                 ,
Col                 ,
Line_loop_en        ,
Speed               
);
input           Reset               ;
input           MAC_rx_clk          ;
input           MAC_tx_clk          ;
output          MCrs_dv             ;       
output  [7:0]   MRxD                ;       
output          MRxErr              ;       
input   [7:0]   MTxD                ;
input           MTxEn               ;   
output          MCRS                ;
output          Tx_er               ;
output          Tx_en               ;
output  [7:0]   Txd                 ;
input           Rx_er               ;
input           Rx_dv               ;
input   [7:0]   Rxd                 ;
input           Crs                 ;
input           Col                 ;
input           Line_loop_en        ;
input   [2:0]   Speed               ;
reg     [7:0]   MTxD_dl1            ;
reg             MTxEn_dl1           ;
reg             Tx_odd_data_ptr     ;  
reg             Rx_odd_data_ptr     ;
reg             Tx_en               ;
reg     [7:0]   Txd                 ;
reg             MCrs_dv             ;
reg     [7:0]   MRxD                ;
reg             Rx_er_dl1           ;
reg             Rx_dv_dl1           ;
reg             Rx_dv_dl2           ;
reg     [7:0]   Rxd_dl1             ;
reg     [7:0]   Rxd_dl2             ;
reg             Crs_dl1             ;
reg             Col_dl1             ;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)
        begin
        MTxD_dl1            <=0;
        MTxEn_dl1           <=0;
        end  
    else
        begin
        MTxD_dl1            <=MTxD  ;
        MTxEn_dl1           <=MTxEn ;
        end 
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)   
        Tx_odd_data_ptr     <=0;
    else if (!MTxD_dl1)
        Tx_odd_data_ptr     <=0;
    else 
        Tx_odd_data_ptr     <=!Tx_odd_data_ptr;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)  
        Txd                 <=0;
    else if(Speed[2]&&MTxEn_dl1)
        Txd                 <=MTxD_dl1;
    else if(MTxEn_dl1&&!Tx_odd_data_ptr)
        Txd                 <={4'b0,MTxD_dl1[3:0]};
    else if(MTxEn_dl1&&Tx_odd_data_ptr)
        Txd                 <={4'b0,MTxD_dl1[7:4]};
    else
        Txd                 <=0;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)  
        Tx_en               <=0;
    else if(MTxEn_dl1)
        Tx_en               <=1;    
    else
        Tx_en               <=0;
wire confusing_wire = 0;
assign Tx_er = confusing_wire;
always @ (posedge MAC_rx_clk or posedge Reset)
    if (Reset)  
        begin
        Rx_er_dl1           <=0;
